// Daniel's criteria + source config + run context. Single source of truth.
const now = new Date();
const runId = `run_${now.toISOString().replace(/[-:T.Z]/g, '').slice(0, 14)}`;

const config = {
  run_id: runId,
  run_timestamp_utc: now.toISOString(),
  dry_run: false,
  criteria: {
    role_keywords: ['senior backend engineer', 'staff backend engineer', 'backend engineer'],
    stack_required: ['python', 'django'],
    stack_preferred: ['postgresql', 'postgres', 'redis', 'aws'],
    experience_years_target: 8,
    salary_min_eur: 90000,
    deal_breakers: ['on-site only', 'on site only', 'onsite only', 'requires us citizenship', 'us citizen only', 'crypto', 'web3', 'blockchain'],
    nice_to_have: ['4-day week', 'four-day week', 'open source', 'series a', 'series b', 'series c'],
    max_listing_age_days: 7,
    location_rule: 'EU-friendly (UTC-1 to UTC+3) OR explicit Europe OR remote anywhere without US restriction'
  },
  sources: [
    { name: 'remoteok.com', weight: 1.0, query_suffix: 'site:remoteok.com' },
    { name: 'weworkremotely.com', weight: 0.9, query_suffix: 'site:weworkremotely.com' },
    { name: 'remotive.com', weight: 0.9, query_suffix: 'site:remotive.com' },
    { name: '4dayweek.io', weight: 0.6, query_suffix: 'site:4dayweek.io' }
  ],
  firecrawl: {
    search_query: '"senior backend engineer" python django remote (site:remoteok.com OR site:weworkremotely.com OR site:remotive.com OR site:4dayweek.io) -crypto -web3',
    search_limit: 20
  },
  candidate_cap: 15,
  deliver_top_n: 10
};

return [{ json: config }];

// Firecrawl Search returns an array of results, each with { url, title, description, markdown? }.
// Normalize to candidate rows. Dedup within this batch by URL.
const raw = $input.all();

const seen = new Set();
const candidates = [];

for (const item of raw) {
  const results = item.json?.data || item.json?.results || item.json?.web || (Array.isArray(item.json) ? item.json : [item.json]);
  const resultArr = Array.isArray(results) ? results : [results];

  for (const r of resultArr) {
    const url = r.url || r.link || r.source_url;
    if (!url || seen.has(url)) continue;
    seen.add(url);

    // Infer source from URL
    let source = 'unknown';
    if (url.includes('remoteok.com')) source = 'remoteok.com';
    else if (url.includes('weworkremotely.com')) source = 'weworkremotely.com';
    else if (url.includes('remotive.com')) source = 'remotive.com';
    else if (url.includes('4dayweek.io')) source = '4dayweek.io';

    candidates.push({
      listing_url: url,
      title: r.title || r.name || '',
      description_snippet: r.description || r.snippet || (r.markdown || '').slice(0, 400),
      source,
      raw_markdown: r.markdown || null
    });
  }
}

// Attach run context from the Config node so downstream nodes have access
const config = $('Config + Run Context').first().json;

return candidates.map(c => ({ json: { ...c, run_id: config.run_id, run_timestamp_utc: config.run_timestamp_utc, criteria: config.criteria } }));

// Two inputs: [0] candidates from Parse Candidates, [1] seen rows from Data Table.
const candidates = $('Parse Candidates').all().map(i => i.json);
const seenRows = $('Get Seen Roles').all().map(i => i.json);
const config = $('Config + Run Context').first().json;

const seenSet = new Set(seenRows.map(r => r.listing_url).filter(Boolean));

// Keep only NEW listings
const fresh = candidates.filter(c => !seenSet.has(c.listing_url));

// Cap at candidate_cap — sort by source weight first so we prioritise higher-weight sources
const sourceWeights = Object.fromEntries(config.sources.map(s => [s.name, s.weight]));
fresh.sort((a, b) => (sourceWeights[b.source] || 0) - (sourceWeights[a.source] || 0));

const capped = fresh.slice(0, config.candidate_cap);

// Attach run context
return capped.map(c => ({ json: { ...c, run_id: config.run_id, run_timestamp_utc: config.run_timestamp_utc, criteria: config.criteria } }));

// Input: agent output (structured). Score it, derive fields, decide keeper vs filtered.
const parsed = $json.output || $json;
const candidate = $('Loop Over Candidates').item.json;
const config = $('Config + Run Context').first().json;

const stackMatched = (parsed.stack_matched_csv || '').toLowerCase().split(',').map(s => s.trim()).filter(Boolean);
const stackMissing = (parsed.stack_missing_csv || '').toLowerCase().split(',').map(s => s.trim()).filter(Boolean);
const obsFacts = (parsed.observed_facts_semicolon || '').toLowerCase();

// Hard filters
let filtered = false;
let reasonCode = '';
let reasonQuote = '';

if (parsed.deal_breaker_hit === true || parsed.deal_breaker_hit === 'true') {
  filtered = true;
  reasonCode = 'deal_breaker:' + (parsed.deal_breaker_reason || 'unknown');
  reasonQuote = parsed.deal_breaker_quote || '';
}

if (!filtered && parsed.salary_max_eur && parsed.salary_max_eur > 0 && parsed.salary_max_eur < config.criteria.salary_min_eur && parsed.salary_confidence === 'high') {
  filtered = true;
  reasonCode = 'salary_below_threshold';
  reasonQuote = `Salary ${parsed.salary_min_eur}-${parsed.salary_max_eur} EUR (source: ${parsed.salary_source})`;
}

if (!filtered && parsed.listing_posted_date) {
  const ageDays = (Date.now() - new Date(parsed.listing_posted_date).getTime()) / 86400000;
  if (ageDays > config.criteria.max_listing_age_days) {
    filtered = true;
    reasonCode = 'listing_too_old';
    reasonQuote = `Posted ${parsed.listing_posted_date}, ${Math.round(ageDays)} days ago`;
  }
}

if (!filtered && !['remote_anywhere', 'remote_eu', 'remote_specific_region'].includes(parsed.remote_type)) {
  filtered = true;
  reasonCode = 'location_mismatch:' + (parsed.remote_type || 'unclear');
  reasonQuote = `remote_type=${parsed.remote_type}, location=${parsed.location}`;
}

// Scoring (ported from Job Finder evaluate-jobs 40/20/20/20)
let score = 40;
const stackKeywords = ['python', 'django', 'postgresql', 'postgres', 'redis', 'aws'];
for (const k of stackKeywords) {
  if (stackMatched.some(s => s.includes(k))) score += 8;
}
score = Math.min(score, 80);

if (!stackMatched.includes('python') && !stackMatched.some(s => s.includes('python'))) score -= 15;
if (!stackMatched.includes('django') && !stackMatched.some(s => s.includes('django'))) score -= 15;

if (parsed.salary_min_eur >= config.criteria.salary_min_eur && parsed.salary_confidence === 'high') score += 10;
if (parsed.salary_source === 'unavailable') score -= 5;

if (parsed.remote_type === 'remote_eu' || parsed.remote_type === 'remote_anywhere') score += 5;

// Nice-to-haves (4-day week, open source, funding)
const fourDayWeek = /4-?day|four-?day/i.test(obsFacts) || candidate.source === '4dayweek.io';
if (fourDayWeek) score += 5;
if (/open.?source/i.test(obsFacts)) score += 3;
if (/series\s+[abc]/i.test(obsFacts)) score += 3;

// Freshness bonus
if (parsed.listing_posted_date) {
  const ageDays = (Date.now() - new Date(parsed.listing_posted_date).getTime()) / 86400000;
  if (ageDays < 3) score += 4;
}

score = Math.max(0, Math.min(100, score));
const band = score >= 75 ? 'High' : score >= 55 ? 'Medium' : 'Low';

// why_not: construct a steelman
const whyNotParts = [];
if (stackMissing.length > 0) whyNotParts.push(`Missing: ${stackMissing.slice(0, 3).join(', ')}.`);
if (parsed.salary_confidence !== 'high') whyNotParts.push(`Salary ${parsed.salary_confidence || 'unknown'} — worth verifying.`);
if (parsed.remote_type === 'remote_specific_region') whyNotParts.push(`Remote scoped to a specific region — check timezone.`);
const whyNot = whyNotParts.length > 0 ? whyNotParts.join(' ') : 'No obvious red flags beyond the listing-level data.';

// Posted display + age_source
let postedDisplay, ageSource;
if (parsed.listing_posted_date) {
  const ageDays = Math.round((Date.now() - new Date(parsed.listing_posted_date).getTime()) / 86400000);
  postedDisplay = `${ageDays}d ago (${parsed.listing_posted_date})`;
  ageSource = 'listing_date';
} else {
  postedDisplay = `first seen ${config.run_timestamp_utc.split('T')[0]}`;
  ageSource = 'first_seen';
}

return [{
  json: {
    listing_url: candidate.listing_url,
    source: candidate.source,
    company: parsed.company || 'unknown',
    role: parsed.role || candidate.title || 'unknown',
    location: parsed.location || 'unknown',
    remote_type: parsed.remote_type || 'unclear',
    posted_display: postedDisplay,
    listing_posted_date: parsed.listing_posted_date || '',
    age_source: ageSource,
    stack_matched_csv: parsed.stack_matched_csv || '',
    stack_missing_csv: parsed.stack_missing_csv || '',
    salary_min_eur: parsed.salary_min_eur || 0,
    salary_max_eur: parsed.salary_max_eur || 0,
    salary_source: parsed.salary_source || 'unavailable',
    salary_confidence: parsed.salary_confidence || 'none',
    observed_facts: parsed.observed_facts_semicolon || '',
    why_it_fits: parsed.why_it_fits || '',
    why_not: whyNot,
    four_day_week: fourDayWeek,
    fit_score: score,
    fit_band: band,
    filtered,
    reason_code: reasonCode,
    reason_quote: reasonQuote,
    run_id: config.run_id,
    discovered_date: config.run_timestamp_utc,
    status: 'new'
  }
}];

// Collect the Score + Decide outputs from the loop. Sort. Annotate top ranks.
const all = $('Score + Decide').all().map(i => i.json);
const kept = all.filter(r => !r.filtered).sort((a, b) => b.fit_score - a.fit_score);
const filtered = all.filter(r => r.filtered);

const topN = 10;
const delivered = kept.slice(0, topN).map((r, idx) => ({ ...r, rank: idx + 1 }));

const config = $('Config + Run Context').first().json;

return [{
  json: {
    run_id: config.run_id,
    run_timestamp_utc: config.run_timestamp_utc,
    week_of: config.run_timestamp_utc.split('T')[0],
    total_candidates: all.length,
    delivered_count: delivered.length,
    filtered_count: filtered.length,
    high_band_count: delivered.filter(r => r.fit_band === 'High').length,
    delivered,
    filtered
  }
}];

// Build the HTML email body. Emotionally calibrated — caring co-pilot, not dashboard.
const d = $json;
const { delivered, filtered, week_of, total_candidates, delivered_count, filtered_count, high_band_count } = d;

const bandColor = { High: '#1f7a3a', Medium: '#8a6d00', Low: '#6b7280' };

const renderRole = (r) => `
  <tr><td style="padding:14px 16px;border-left:3px solid ${bandColor[r.fit_band] || '#6b7280'};background:#fafafa;border-radius:4px;">
    <div style="display:flex;justify-content:space-between;align-items:baseline;">
      <strong style="font-size:15px;">#${r.rank} · ${r.company}</strong>
      <span style="font-size:12px;color:${bandColor[r.fit_band]};font-weight:600;">${r.fit_band} · ${r.fit_score}/100</span>
    </div>
    <div style="font-size:13px;color:#444;margin:2px 0 8px 0;">${r.role} · ${r.location} · ${r.posted_display}</div>
    <div style="font-size:13px;line-height:1.5;">
      <strong>Why it fits:</strong> ${r.why_it_fits}<br>
      <strong style="color:#6b7280;">Worth checking:</strong> <span style="color:#6b7280;">${r.why_not}</span><br>
      <strong>Salary:</strong> ${r.salary_source === 'unavailable' ? 'not listed (worth verifying in the application)' : `EUR ${r.salary_min_eur?.toLocaleString() || '?'}-${r.salary_max_eur?.toLocaleString() || '?'} (${r.salary_confidence} confidence, from ${r.salary_source})`} ${r.four_day_week ? ' · 🗓 <em>4-day week</em>' : ''}
    </div>
    <div style="margin-top:10px;font-size:13px;">
      <a href="${r.listing_url}" style="color:#1f3b5b;font-weight:600;text-decoration:none;margin-right:14px;">View listing →</a>
    </div>
  </td></tr>`;

const highs = delivered.filter(r => r.fit_band === 'High');
const mediums = delivered.filter(r => r.fit_band === 'Medium');
const lows = delivered.filter(r => r.fit_band === 'Low');

const section = (title, roles) => roles.length === 0 ? '' : `
  <h3 style="margin:24px 0 10px 0;font-size:12px;letter-spacing:0.1em;text-transform:uppercase;color:#6b7280;">${title}</h3>
  <table style="width:100%;border-collapse:separate;border-spacing:0 8px;">${roles.map(renderRole).join('')}</table>`;

const filteredOutSection = filtered.length === 0 ? '' : `
  <details style="margin-top:30px;padding:12px 16px;background:#f7f7f5;border-radius:4px;">
    <summary style="font-size:13px;color:#6b7280;cursor:pointer;">See the ${filtered.length} I ruled out (and the exact quote that did it)</summary>
    <table style="margin-top:10px;width:100%;font-size:12px;border-collapse:collapse;">
      ${filtered.slice(0, 20).map(f => `<tr><td style="padding:6px 0;border-bottom:1px solid #e5e7eb;"><strong>${f.company || '?'}</strong> · ${f.role || '?'}<br><em style="color:#6b7280;">${f.reason_code}</em><br><span style="color:#888;font-size:11px;">"${(f.reason_quote || '').slice(0,180)}"</span></td></tr>`).join('')}
    </table>
  </details>`;

const openingLine = high_band_count > 0
  ? `${high_band_count} strong ${high_band_count === 1 ? 'match' : 'matches'} this week. Enough to move on.`
  : delivered_count > 0
    ? `No High-band roles this week, but ${delivered_count} defensible ${delivered_count === 1 ? 'match' : 'matches'} to scan.`
    : `Zero matches this week. That's the filter working, not failing — the sources I checked are logged below.`;

const html = `<!DOCTYPE html>
<html><body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;color:#0e1216;max-width:680px;margin:0 auto;padding:24px;line-height:1.5;">
  <p style="font-size:16px;margin-bottom:4px;">Morning Daniel,</p>
  <p style="font-size:15px;margin-top:0;color:#3a4048;">
    ${openingLine}<br>
    ${total_candidates} listings checked · ${delivered_count} delivered · ${filtered_count} filtered out with evidence.
  </p>

  ${section('The ones to look at first', highs)}
  ${section('Worth a look', mediums)}
  ${section('Optional — lower priority', lows)}
  ${filteredOutSection}

  <p style="margin-top:30px;font-size:12px;color:#6b7280;border-top:1px solid #e5e7eb;padding-top:12px;">
    Finding the right role takes time, not effort. You're doing the work — let me do the sifting.<br>
    <em>Week of ${week_of} · run ${d.run_id}</em>
  </p>
</body></html>`;

return [{ json: { ...d, email_subject: `Your Monday roles, Daniel — ${delivered_count} found, ${high_band_count} ready to apply`, email_html: html } }];
